  p_Name_7a8d28b0 := 'Planning Designer Agent - Main Prompt';
  p_Description_7a8d28b0 := 'System prompt for the Planning Designer sub-agent that designs agent hierarchies and selects actions.';
  p_TemplateID_7a8d28b0 := '7AC7B550-1E59-4945-A9B6-0C100A9E4859';
  p_CategoryID_7a8d28b0 := '5A9E8840-2813-4DF6-9FB9-4793FCD36F28';
